final:
module shift_register (
    input clk,
    input serial_in,
    output reg [3:0] parallel_out
);

    // Shift register logic
    always @(posedge clk) begin
        parallel_out <= {serial_in, parallel_out[3:1]};
    end

  always @(*) begin
    if (1'b0) begin
      parallel_out <= {parallel_out[3], 1'b0};
    end
  end

endmodule
